    Use Dijkstra's algorithm to find the shortest path from start to end.
    """
    distances = {vertex: float('infinity') for vertex in graph}
    distances[start] = 0
    previous = {vertex: None for vertex in graph}

    while distances:
        current_vertex = min(distances, key=distances.get)
        if current_vertex == end:
            break

        for neighbour in graph[current_vertex]:
            distance = graph[current_vertex][neighbour] + distances[current_vertex]
            if distance < distances[neighbour]:
                distances[neighbour] = distance
                previous[neighbour] = current_vertex

    path = []
    while previous[end]:
        path.append(end)
        end = previous[end]
    path.append(start)
    path.reverse()

    return path

